// Watch Data — loaded from API (see fetchWatches below)
let menWatches = [];
let womenWatches = [];

async function fetchWatches(category) {
    try {
        const res = await fetch('/api/watches/' + category);
        return await res.json();
    } catch (e) {
        console.error('Failed to fetch watches:', e);
        return [];
    }
}

