// Display Watches
function displayWatches(watches, containerId, limit = null) {
    const container = document.getElementById(containerId);
    if (!container) return;
    
    const watchesToShow = limit ? watches.slice(0, limit) : watches;
    container.innerHTML = watchesToShow.map((watch, index) => {
        const msg = encodeURIComponent(`Hi, I'm interested in this watch:\n\nBrand: ${watch.brand}\nName: ${watch.name}\nPrice: ${watch.price}\nType: ${watch.type}\nDescription: ${watch.desc}`);
        return `
        <div class="watch-card" style="position:relative;" onclick="showWatchDetails(${JSON.stringify(watch).replace(/"/g, '&quot;')})">
            <img src="${watch.img}" alt="${watch.name}">
            <div class="watch-brand">${watch.brand}</div>
            <div class="watch-name">${watch.name}</div>
            <div class="watch-price">${watch.price}</div>
            <div class="watch-desc">${watch.desc}</div>
            <div class="watch-type">${watch.type}</div>
            <a href="https://wa.me/971501234567?text=${msg}" target="_blank" rel="noopener noreferrer" onclick="event.stopPropagation()" style="display:flex;align-items:center;justify-content:center;gap:8px;margin-top:15px;padding:10px;background:#25D366;color:#fff;text-decoration:none;font-size:14px;font-weight:600;border-radius:5px;"><img src="https://upload.wikimedia.org/wikipedia/commons/6/6b/WhatsApp.svg" style="width:20px;height:20px;"> WhatsApp</a>
        </div>`;
    }).join('');
}

// Show Watch Details Modal
function showWatchDetails(watch) {
    const modal = document.getElementById('watchModal') || createWatchModal();
    
    document.getElementById('modalImage').src = watch.img;
    document.getElementById('modalBrand').textContent = watch.brand;
    document.getElementById('modalName').textContent = watch.name;
    document.getElementById('modalPrice').textContent = watch.price;
    document.getElementById('modalType').textContent = watch.type;
    document.getElementById('modalDesc').textContent = watch.desc;

    const msg = encodeURIComponent(`Hi, I'm interested in this watch:%0A%0ABrand: ${watch.brand}%0AName: ${watch.name}%0APrice: ${watch.price}%0AType: ${watch.type}%0ADescription: ${watch.desc}`);
    document.getElementById('modalWhatsApp').href = `https://wa.me/971501234567?text=${msg}`;
    
    modal.style.display = 'flex';
}

// Create Watch Modal
function createWatchModal() {
    const modal = document.createElement('div');
    modal.id = 'watchModal';
    modal.innerHTML = `
        <div style="position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.9); display: none; align-items: center; justify-content: center; z-index: 2000;">
            <div style="background: #0a0a0a; border: 2px solid #D4AF37; padding: 40px; max-width: 500px; width: 90%; border-radius: 10px; position: relative;">
                <button onclick="closeWatchModal()" style="position: absolute; top: 15px; right: 20px; background: none; border: none; color: #D4AF37; font-size: 24px; cursor: pointer;">&times;</button>
                <div style="text-align: center;">
                    <img id="modalImage" style="width: 200px; height: 200px; object-fit: contain; margin-bottom: 20px; background: #000; border-radius: 10px;">
                    <div id="modalBrand" style="color: #D4AF37; font-size: 18px; font-weight: 600; margin-bottom: 10px;"></div>
                    <div id="modalName" style="font-size: 24px; margin-bottom: 15px; color: #fff;"></div>
                    <div id="modalPrice" style="color: #D4AF37; font-size: 28px; font-weight: 600; margin-bottom: 15px;"></div>
                    <div style="display: inline-block; padding: 8px 20px; background: rgba(212, 175, 55, 0.2); color: #D4AF37; font-size: 14px; border: 1px solid #D4AF37; margin-bottom: 20px; border-radius: 5px;">
                        <span id="modalType"></span>
                    </div>
                    <div id="modalDesc" style="color: #ccc; font-size: 16px; line-height: 1.5; margin-bottom: 20px;"></div>
                    <a id="modalWhatsApp" href="#" target="_blank" rel="noopener noreferrer" style="display: inline-block; padding: 12px 30px; background: #25D366; color: #fff; text-decoration: none; font-size: 16px; font-weight: 600; border-radius: 5px;">💬 Enquire on WhatsApp</a>
                </div>
            </div>
        </div>
    `;
    document.body.appendChild(modal);
    return modal;
}

// Close Watch Modal
function closeWatchModal() {
    document.getElementById('watchModal').style.display = 'none';
}

// Search Functionality
function searchWatches() {
    const brand = document.getElementById('searchBrand').value.toLowerCase();
    const type = document.getElementById('searchType').value;
    
    if (brand || type) {
        localStorage.setItem('searchBrand', brand);
        localStorage.setItem('searchType', type);
        window.location.href = 'men.html';
    }
}

// Filter Watches
function filterWatches(watches) {
    const brand = document.getElementById('filterBrand')?.value.toLowerCase() || '';
    const type = document.getElementById('filterType')?.value || '';
    
    return watches.filter(watch => {
        const matchBrand = !brand || watch.brand.toLowerCase().includes(brand);
        const matchType = !type || watch.type === type;
        return matchBrand && matchType;
    });
}
